{"command":"@'
Add-Type -AssemblyName System.IO.Compression.FileSystem
$path = Join-Path (Get-Location) 'sources/raw/界定问题六问法.docx'
$zip = [System.IO.Compression.ZipFile]::OpenRead($path)
try {
  $entry = $zip.Entries | Where-Object { $_.FullName -eq 'word/document.xml' }
  $reader = New-Object System.IO.StreamReader($entry.Open())
  $xml = $reader.ReadToEnd()
  $reader.Close()
  $xml = [regex]::Replace($xml, '</w:p>', "`n")
  $xml = [regex]::Replace($xml, '<[^>]+>', '')
  $xml = [System.Net.WebUtility]::HtmlDecode($xml)
  $lines = $xml -split "`n" | ForEach-Object { $_.Trim() } | Where-Object { $_ }
  $patterns = '第三问','第四问','差距','目的','0.5Why','0.5','真正的问题'
  foreach ($pattern in $patterns) {
    "--- PATTERN: $pattern ---"
    $matches = $lines | Select-String -Pattern $pattern -SimpleMatch
    foreach ($m in $matches | Select-Object -First 12) { $m.Line }
  }
} finally {
  $zip.Dispose()
}
'@ | powershell -NoProfile -Command -","workdir":"D:\00容器\yc\yc_think","timeout_ms":20000}

